+                config.filters.seed = Some(seed);
+            }
+            "--component" => {
+                index += 1;
+                if index >= args.len() {
+                    return Err("--component requires a value".to_owned());
+                }
+                config.filters.component = Some(args[index].clone());
+            }
+            "--severity" => {
+                index += 1;
+                if index >= args.len() {
